        // C: setgcparam(g->genmajormul, LUAI_GENMAJORMUL); → g->genmajormul = LUAI_GENMAJORMUL / 4
        // macros.tsv: setgcparam → p = v / 4
        genmajormul: (LUAI_GENMAJORMUL / 4) as u8,
        // C: g->gcstp = GCSTPGC;
        gcstp: GCSTPGC,
        // C: g->gcemergency = 0;
