// C: LUA_API int lua_type (lua_State *L, int idx)
pub fn lua_type_at(state: &LuaState, idx: i32) -> LuaType {
    // C: return (isvalid(L, o) ? ttype(o) : LUA_TNONE);
    if !is_valid_index(state, idx) {
        return LuaType::None;
    }
    index_to_value(state, idx).base_type()
}

