const LUA_YIELD_STATUS: i32 = 1;

// C: LUA_ENV — the name of the global environment upvalue
// macros.tsv: LUA_ENV → const LUA_ENV: &[u8] = b"_ENV"
const LUA_ENV: &[u8] = b"_ENV";

